const QUESTIONS_CISSP_C2 = [
  { id:30301, domain:3, level:2, question:"Which security model enforces confidentiality by preventing subjects from reading data at a higher classification level?", options:["A Clark-Wilson model","B Brewer-Nash model","C Biba model","D Bell-LaPadula model"], correct:3, explanation:"Bell-LaPadula enforces confidentiality with 'no read up' (simple security property) and 'no write down' (star property), preventing subjects from reading above their clearance level." },
  { id:30302, domain:3, level:2, question:"What does the Clark-Wilson integrity model primarily protect against?", options:["A Unauthorized disclosure of classified data","B Replay attacks in network communications","C Unauthorized modification of data by enforcing well-formed transactions","D Denial of service attacks on critical systems"], correct:2, explanation:"Clark-Wilson protects data integrity by requiring all changes go through certified transformation procedures (TPs), ensuring only well-formed transactions occur." },
  { id:30303, domain:3, level:1, question:"Which evaluation criteria provides a common set of requirements for security products recognized internationally?", options:["A FIPS 140-2","B ISO/IEC 27001","C TCSEC (Orange Book)","D Common Criteria (ISO 15408)"], correct:3, explanation:"Common Criteria (ISO/IEC 15408) is an internationally recognized framework allowing security products to be evaluated against defined Protection Profiles and Evaluation Assurance Levels." },
  { id:30304, domain:3, level:2, question:"What is the primary purpose of a Trusted Platform Module (TPM)?", options:["A Encrypting all data on a network segment","B Providing hardware-based cryptographic key storage and platform integrity measurement","C Managing user authentication for enterprise applications","D Generating pseudo-random numbers for session tokens"], correct:1, explanation:"A TPM is a hardware chip that securely stores cryptographic keys and measures platform integrity through hash values, enabling trusted boot and remote attestation." },
  { id:30305, domain:3, level:2, question:"Which type of cipher operates on fixed-size blocks of data, transforming each block using the same key?", options:["A Stream cipher","B Substitution cipher","C Block cipher","D One-time pad"], correct:2, explanation:"Block ciphers (e.g., AES, DES) process fixed-size blocks of plaintext and produce fixed-size ciphertext blocks, using the same key for each block transformation." },
  { id:30306, domain:3, level:2, question:"What is the purpose of cipher block chaining (CBC) mode in block cipher encryption?", options:["A To increase the key size for stronger encryption","B To reduce the computational overhead of block encryption","C To allow parallel processing of all cipher blocks simultaneously","D To XOR each plaintext block with the previous ciphertext block before encryption"], correct:3, explanation:"In CBC mode, each plaintext block is XORed with the preceding ciphertext block before encryption, ensuring identical plaintext blocks produce different ciphertext and providing error propagation." },
  { id:30307, domain:3, level:1, question:"Which cryptographic algorithm is considered asymmetric?", options:["A RSA","B 3DES","C AES-256","D Blowfish"], correct:0, explanation:"RSA is an asymmetric algorithm using a public/private key pair. AES-256, 3DES, and Blowfish are all symmetric algorithms using a single shared secret key." },
  { id:30308, domain:3, level:2, question:"What is the primary security advantage of elliptic curve cryptography (ECC) over RSA?", options:["A ECC is easier to implement in software than RSA","B ECC provides stronger encryption with shorter key lengths","C ECC supports digital signatures but RSA does not","D ECC is not vulnerable to man-in-the-middle attacks"], correct:1, explanation:"ECC provides equivalent security to RSA with significantly shorter key lengths (e.g., 256-bit ECC ≈ 3072-bit RSA), making it more efficient for mobile and constrained devices." },
  { id:30309, domain:3, level:2, question:"Which principle states that a system should have the minimum number of trusted components necessary to enforce security policy?", options:["A Least privilege","B Defense in depth","C Economy of mechanism","D Separation of duties"], correct:2, explanation:"Economy of mechanism (also called simplicity) states that security mechanisms should be as simple as possible, reducing the trusted computing base and minimizing potential vulnerabilities." },
  { id:30310, domain:3, level:2, question:"What does 'open design' mean as a security design principle?", options:["A Security does not depend on secrecy of the design; only keys are secret","B Security relies on the secrecy of the design and algorithms","C The system is accessible to all users without authentication","D Source code is publicly available for peer review"], correct:0, explanation:"Open design principle states that system security should not rely on keeping the design secret (security through obscurity). Only the keys should be kept secret, making algorithms publicly scrutinizable." },
  { id:30311, domain:3, level:2, question:"In the context of security architecture, what is the Trusted Computing Base (TCB)?", options:["A All data classified as sensitive within an organization","B The group of security administrators managing the system","C The set of all hardware components in a secure system","D The totality of protection mechanisms within a computer system responsible for enforcing security policy"], correct:3, explanation:"The TCB is the combination of all hardware, software, and firmware that enforces the security policy of a system. Minimizing the TCB reduces the attack surface and simplifies verification." },
  { id:30312, domain:3, level:1, question:"Which type of malware replicates itself by attaching to legitimate programs and spreads when those programs are executed?", options:["A Rootkit","B Virus","C Trojan horse","D Worm"], correct:1, explanation:"A virus attaches itself to legitimate host programs and requires user action (executing the host program) to spread. Worms spread without user interaction; trojans disguise as legitimate software; rootkits hide their presence." },
  { id:30313, domain:3, level:2, question:"What is the primary difference between a worm and a virus?", options:["A Viruses target network devices while worms target endpoints","B Worms encrypt files while viruses delete them","C Worms self-replicate across networks without requiring a host file","D Worms require administrator privileges while viruses do not"], correct:2, explanation:"Worms are self-contained programs that replicate and spread across networks independently without needing to attach to host files. Viruses require host programs to propagate." },
  { id:30314, domain:3, level:2, question:"Which vulnerability allows an attacker to execute arbitrary commands by manipulating input that is passed to a system shell?", options:["A Command injection","B SQL injection","C Cross-site scripting","D Directory traversal"], correct:0, explanation:"Command injection occurs when user-supplied input is passed unsanitized to a system shell or interpreter, allowing attackers to execute arbitrary OS commands with the application's privileges." },
  { id:30315, domain:3, level:2, question:"What is a race condition vulnerability in software?", options:["A Software that runs slower than expected under load","B An error caused by exceeding memory allocation limits","C A flaw where system behavior depends on the timing of uncontrollable events","D A condition where two processes compete for limited CPU cycles"], correct:2, explanation:"Race conditions occur when system behavior depends on the sequence or timing of events (e.g., two processes accessing shared data simultaneously), potentially leading to security exploits like TOCTOU attacks." },
  { id:30316, domain:4, level:2, question:"Which OSI layer is responsible for end-to-end communication and error recovery between hosts?", options:["A Data Link layer (Layer 2)","B Network layer (Layer 3)","C Transport layer (Layer 4)","D Session layer (Layer 5)"], correct:2, explanation:"The Transport layer (Layer 4) provides end-to-end communication services, error recovery, flow control, and multiplexing. TCP and UDP operate at this layer." },
  { id:30317, domain:4, level:1, question:"What is the primary purpose of Network Address Translation (NAT)?", options:["A To encrypt traffic between internal and external networks","B To route packets between different network segments","C To authenticate users before granting network access","D To map private IP addresses to public IP addresses for internet communication"], correct:3, explanation:"NAT allows multiple devices with private IP addresses to share a single public IP address, conserving public IP space and providing a degree of network address obscuration." },
  { id:30318, domain:4, level:2, question:"Which protocol provides authentication and encryption for IP packets at the network layer?", options:["A HTTPS","B SSL/TLS","C SSH","D IPSec"], correct:3, explanation:"IPSec operates at the Network layer (Layer 3) and provides authentication (AH header) and encryption (ESP header) for IP packets, securing communication at the network level." },
  { id:30319, domain:4, level:2, question:"In IPSec, what is the difference between Transport mode and Tunnel mode?", options:["A Transport mode is used for host-to-host; Tunnel mode is only for site-to-site VPNs","B Transport mode encrypts only the payload; Tunnel mode encapsulates the entire original IP packet","C Transport mode encrypts the entire IP packet; Tunnel mode encrypts only the payload","D Transport mode uses AH; Tunnel mode uses ESP"], correct:1, explanation:"In Transport mode, only the IP payload is protected; the original IP header remains intact. In Tunnel mode, the entire original IP packet is encapsulated within a new IP packet with a new header, commonly used for VPNs." },
  { id:30320, domain:4, level:2, question:"Which wireless security protocol uses the CCMP encryption mode based on AES?", options:["A WPA (TKIP)","B WPA2/WPA3","C WEP","D WPS"], correct:1, explanation:"WPA2 (and WPA3) use CCMP (Counter Mode with CBC-MAC Protocol), which is based on AES-128, providing strong encryption and integrity protection. WPA uses TKIP; WEP uses RC4." },
  { id:30321, domain:4, level:1, question:"What type of attack involves intercepting and modifying communications between two parties without their knowledge?", options:["A Denial of service attack","B Session hijacking","C Man-in-the-middle attack","D Replay attack"], correct:2, explanation:"A man-in-the-middle (MITM) attack occurs when an attacker secretly intercepts and potentially alters communication between two parties, who believe they are communicating directly with each other." },
  { id:30322, domain:4, level:2, question:"What is the primary function of a proxy firewall (application layer gateway)?", options:["A Terminating and re-establishing connections while inspecting application layer data","B Filtering packets based solely on source and destination IP addresses","C Providing stateful inspection of TCP session state","D Encrypting all traffic passing through the network perimeter"], correct:0, explanation:"Proxy firewalls (application layer gateways) terminate client connections, inspect application-layer content, and create new connections to the destination, providing deep content inspection and hiding internal network topology." },
  { id:30323, domain:4, level:2, question:"Which network attack exploits the trust relationship between IP addresses by falsifying the source address in packets?", options:["A DNS hijacking","B ARP poisoning","C MAC flooding","D IP spoofing"], correct:3, explanation:"IP spoofing involves crafting packets with forged source IP addresses to impersonate trusted hosts, bypass access controls, or facilitate other attacks while hiding the attacker's true identity." },
  { id:30324, domain:4, level:2, question:"What does 802.1X provide in a network security context?", options:["A Port-based network access control requiring authentication before granting access","B VLAN configuration and management for network segmentation","C Wireless encryption using CCMP/AES","D Quality of service prioritization for network traffic"], correct:0, explanation:"IEEE 802.1X provides port-based Network Access Control (PNAC), requiring devices to authenticate (typically via EAP) through an authentication server before being granted network access." },
  { id:30325, domain:4, level:2, question:"What is a botnet?", options:["A A type of intrusion detection system using agent-based monitoring","B A collection of compromised computers controlled by an attacker for malicious purposes","C A network of servers providing distributed computing resources","D A secure overlay network for anonymous communications"], correct:1, explanation:"A botnet is a network of malware-infected computers (bots/zombies) controlled by a command-and-control server. Attackers use botnets for spam, DDoS attacks, credential theft, and other malicious activities." },
  { id:30326, domain:4, level:1, question:"Which protocol is primarily used to dynamically assign IP addresses to network devices?", options:["A DNS","B ICMP","C ARP","D DHCP"], correct:3, explanation:"Dynamic Host Configuration Protocol (DHCP) automatically assigns IP addresses, subnet masks, default gateways, and other network parameters to devices when they connect to a network." },
  { id:30327, domain:4, level:2, question:"What security weakness does DHCP snooping address?", options:["A ARP spoofing attacks on the local network segment","B Rogue DHCP servers distributing malicious network configuration to clients","C DNS cache poisoning attacks on the network","D MAC address flooding that overwhelms switch tables"], correct:1, explanation:"DHCP snooping is a switch security feature that filters DHCP messages, allowing only trusted DHCP server responses, preventing rogue DHCP servers from distributing incorrect gateway or DNS information to clients." },
  { id:30328, domain:4, level:2, question:"Which attack type exhausts server resources by sending SYN packets without completing the TCP three-way handshake?", options:["A UDP flood attack","B SYN flood attack","C Smurf attack","D Fraggle attack"], correct:1, explanation:"A SYN flood attack sends many TCP SYN packets without completing the handshake, filling the server's connection queue with half-open connections and exhausting resources, causing denial of service." },
  { id:30329, domain:4, level:2, question:"What is the purpose of BGP (Border Gateway Protocol) route filtering?", options:["A To authenticate OSPF adjacencies between routers","B To prevent the propagation of invalid or malicious routing information between networks","C To optimize packet forwarding within a single network","D To encrypt routing information between autonomous systems"], correct:1, explanation:"BGP route filtering controls which routes are accepted from and advertised to neighbors, preventing route hijacking, prefix hijacking, and the propagation of misconfigured or malicious routing information." },
  { id:30330, domain:4, level:2, question:"What does the term 'split tunneling' refer to in VPN configurations?", options:["A Allowing some traffic to go through the VPN while other traffic routes directly to the internet","B Dividing VPN traffic between multiple tunnels for load balancing","C Creating separate encrypted channels for different security classifications","D Splitting the VPN key between two administrators for dual control"], correct:0, explanation:"Split tunneling allows VPN users to send organization-bound traffic through the encrypted VPN tunnel while routing internet-bound traffic directly to the internet, bypassing the VPN, which may reduce security visibility." },
  { id:30331, domain:5, level:1, question:"Which access control model grants access based on the subject's clearance level and the object's classification label?", options:["A Discretionary Access Control (DAC)","B Role-Based Access Control (RBAC)","C Mandatory Access Control (MAC)","D Attribute-Based Access Control (ABAC)"], correct:2, explanation:"Mandatory Access Control (MAC) grants access based on security labels assigned to subjects (clearances) and objects (classifications). The system, not the owner, enforces access decisions based on policy." },
  { id:30332, domain:5, level:1, question:"In Role-Based Access Control (RBAC), permissions are assigned to what primary entity?", options:["A Roles, which are then assigned to users","B Individual user accounts","C Security groups based on department","D Objects based on their sensitivity classification"], correct:0, explanation:"In RBAC, permissions are assigned to roles (job functions), and users are assigned to roles. This simplifies administration since changing permissions for a job function only requires updating the role." },
  { id:30333, domain:5, level:2, question:"What is the primary advantage of Attribute-Based Access Control (ABAC) over traditional RBAC?", options:["A ABAC provides fine-grained access control based on multiple attributes of users, resources, and environment","B ABAC is simpler to implement and administer than RBAC","C ABAC eliminates the need for authentication before authorization","D ABAC is the only model compliant with government security regulations"], correct:0, explanation:"ABAC evaluates multiple attributes (user attributes, resource attributes, environmental conditions) to make access decisions, enabling very granular policies like 'grant access only during business hours from corporate devices.'" },
  { id:30334, domain:5, level:2, question:"What is the purpose of an Identity Provider (IdP) in federated identity management?", options:["A To provision user accounts in multiple systems simultaneously","B To store and manage all application user databases","C To encrypt all communications between users and applications","D To authenticate users and assert their identity to relying parties via trust relationships"], correct:3, explanation:"An Identity Provider authenticates users, maintains their identity information, and provides identity assertions (tokens/claims) to relying party services (Service Providers), enabling Single Sign-On across federated systems." },
  { id:30335, domain:5, level:2, question:"Which authentication protocol is commonly used for web-based Single Sign-On, issuing tokens rather than passwords?", options:["A LDAP","B Kerberos","C RADIUS","D SAML (Security Assertion Markup Language)"], correct:3, explanation:"SAML is an XML-based open standard for exchanging authentication and authorization data between identity providers and service providers, enabling browser-based SSO by passing XML assertions." },
  { id:30336, domain:5, level:2, question:"In Kerberos authentication, what is the primary role of the Ticket Granting Service (TGS)?", options:["A To verify the user's initial identity and issue a Ticket Granting Ticket","B To store the master database of all user credentials and secrets","C To encrypt all network traffic between client and server","D To issue service tickets for specific resources after presenting a valid TGT"], correct:3, explanation:"The TGS issues service tickets for specific services when clients present a valid Ticket Granting Ticket (TGT). The TGT is issued by the Authentication Service (AS) after initial authentication." },
  { id:30337, domain:5, level:2, question:"What is the concept of 'just-in-time' access provisioning in privileged access management?", options:["A Provisioning user accounts immediately upon hire without delay","B Automatically revoking access after a fixed time period regardless of activity","C Scheduling privileged access reviews on a regular calendar basis","D Granting elevated privileges only when needed and automatically removing them after the task"], correct:3, explanation:"Just-in-time access grants privileged access temporarily for specific tasks and automatically revokes it afterward, minimizing the exposure window for privileged accounts and following the principle of least privilege." },
  { id:30338, domain:5, level:2, question:"What does OAuth 2.0 primarily provide?", options:["A Authentication of user identity for web applications","B Digital signature verification for software packages","C Encryption of data transmitted between clients and APIs","D Authorization framework allowing third-party applications to access resources without sharing credentials"], correct:3, explanation:"OAuth 2.0 is an authorization framework that enables applications to obtain limited access to user accounts on another service using access tokens, without exposing user credentials to the third-party application." },
  { id:30339, domain:5, level:2, question:"Which biometric characteristic has the highest uniqueness and is considered among the most reliable for authentication?", options:["A Fingerprint","B Voice recognition","C Iris pattern","D Facial geometry"], correct:2, explanation:"Iris patterns are highly unique (even between identical twins and between left/right eyes), stable over time, and difficult to forge, making iris recognition among the most accurate biometric methods." },
  { id:30340, domain:5, level:2, question:"What does the Crossover Error Rate (CER) measure in biometric systems?", options:["A The maximum number of authentication attempts before lockout","B The percentage of biometric data compromised in a breach","C The point where false acceptance rate equals false rejection rate, indicating overall accuracy","D The rate at which enrolled users lose their biometric credentials over time"], correct:2, explanation:"CER (also called Equal Error Rate or EER) is the point where FAR equals FRR. A lower CER indicates a more accurate biometric system. It is used to compare the accuracy of different biometric technologies." },
  { id:30341, domain:5, level:2, question:"What is the primary security concern with password hash storage using MD5 or SHA-1?", options:["A These algorithms produce hashes that are too short for adequate security","B These algorithms cannot be used with salting to improve security","C These algorithms are fast, making brute-force and rainbow table attacks efficient","D These algorithms produce reversible hashes that reveal the original password"], correct:2, explanation:"MD5 and SHA-1 are fast general-purpose hashes. Their speed makes them unsuitable for passwords because attackers can compute billions of hash attempts per second. Password hashing should use slow functions like bcrypt or Argon2." },
  { id:30342, domain:5, level:2, question:"Which provisioning process ensures that access rights are removed when an employee leaves an organization?", options:["A Privilege escalation review","B Access recertification","C Deprovisioning","D Access certification"], correct:2, explanation:"Deprovisioning is the process of revoking a user's access rights, disabling accounts, and removing privileges when they leave the organization or change roles, preventing unauthorized access after separation." },
  { id:30343, domain:5, level:1, question:"What is the 'something you have' authentication factor?", options:["A A biometric characteristic unique to the individual","B A password or PIN known only to the user","C A physical token, smart card, or mobile device possessed by the user","D A location-based check verifying the user's position"], correct:2, explanation:"'Something you have' is a possession factor—a physical item like a hardware token, smart card, key fob, or mobile authenticator app. Multi-factor authentication combines this with other factor types." },
  { id:30344, domain:5, level:2, question:"What is the primary purpose of Privileged Access Management (PAM) solutions?", options:["A Managing end-user passwords across multiple applications","B Providing single sign-on for regular user accounts across enterprise applications","C Controlling, monitoring, and auditing privileged account usage to minimize insider threat risk","D Automating the provisioning of new user accounts in directory services"], correct:2, explanation:"PAM solutions control access to privileged accounts (admin, root, service accounts), enforce least privilege, record privileged sessions, and provide audit trails to detect and prevent misuse of elevated credentials." },
  { id:30345, domain:5, level:2, question:"What does the concept of 'identity federation' enable?", options:["A Automatic synchronization of passwords between multiple identity stores","B Central storage of all user identities across every connected organization","C Mandatory use of the same authentication protocol across all federated systems","D Trust relationships between domains allowing users to authenticate once and access resources across boundaries"], correct:3, explanation:"Identity federation establishes trust between organizations (or domains) so that authenticated users can access resources in partner organizations without needing separate accounts, based on trusted identity assertions." },
  { id:30346, domain:5, level:2, question:"Which protocol is commonly used for centralized authentication, authorization, and accounting in network access scenarios?", options:["A RADIUS","B LDAP","C OAuth 2.0","D TACACS+"], correct:0, explanation:"RADIUS (Remote Authentication Dial-In User Service) provides centralized AAA services for network access, commonly used for VPN, Wi-Fi, and dial-up authentication. TACACS+ provides similar functionality with additional features for device administration." },
  { id:30347, domain:5, level:2, question:"What is the difference between authentication and authorization?", options:["A Authentication applies to users; authorization applies only to service accounts","B Authentication determines what you can do; authorization verifies who you are","C Authentication is performed by the client; authorization is performed by the server","D Authentication verifies who you are; authorization determines what you are permitted to do"], correct:3, explanation:"Authentication verifies identity (who are you?), while authorization determines access rights (what are you allowed to do?). Both are required for secure access control, but they are distinct processes." },
  { id:30348, domain:5, level:2, question:"What is a directory service's primary function in identity management?", options:["A Providing encrypted storage for user credentials and private keys","B Storing and providing access to information about network resources and users","C Auditing and logging all user access events for compliance reporting","D Generating one-time passwords for multi-factor authentication"], correct:1, explanation:"Directory services (e.g., Active Directory, LDAP) store structured information about network objects (users, groups, computers, resources) and provide query and update capabilities, serving as the foundation for authentication and authorization." },
  { id:30349, domain:5, level:2, question:"What is the purpose of access recertification (access review) campaigns?", options:["A Resetting all user passwords on a scheduled basis for security hygiene","B Auditing failed authentication attempts to detect potential intrusions","C Updating access control policies to reflect new business requirements","D Periodically reviewing and confirming that user access rights remain appropriate and necessary"], correct:3, explanation:"Access recertification involves periodic reviews by managers or data owners to confirm that users' access rights are still appropriate for their current role, removing unnecessary or excessive access to maintain least privilege." },
  { id:30350, domain:5, level:2, question:"Which concept ensures that no single person can complete a sensitive transaction or task without involvement from another person?", options:["A Least privilege","B Separation of duties","C Need to know","D Job rotation"], correct:1, explanation:"Separation of duties (SoD) divides critical tasks between multiple people so that no single individual can misuse access or commit fraud without detection. For example, the person who authorizes payments should not also process them." },
  { id:30351, domain:3, level:2, question:"Which security model is based on the concept of Chinese Wall and prevents conflicts of interest?", options:["A Bell-LaPadula model","B Brewer-Nash (Chinese Wall) model","C Biba model","D Clark-Wilson model"], correct:1, explanation:"The Brewer-Nash model (Chinese Wall) prevents conflicts of interest by restricting access to competing companies' data once a user has accessed one company's data, commonly used in financial and consulting environments." },
  { id:30352, domain:3, level:2, question:"What is the primary purpose of a hardware security module (HSM)?", options:["A Providing a secure network perimeter for server rooms","B Generating, storing, and managing cryptographic keys in tamper-resistant hardware","C Enforcing hardware-level access controls for server BIOS settings","D Monitoring hardware performance and detecting physical intrusions"], correct:1, explanation:"HSMs are dedicated hardware devices that generate, store, and protect cryptographic keys and perform cryptographic operations in a tamper-resistant environment, protecting keys from extraction even by administrators." },
  { id:30353, domain:3, level:2, question:"What is steganography used for in information security?", options:["A Encrypting data using a one-time pad for perfect secrecy","B Authenticating digital messages using asymmetric key pairs","C Hiding secret information within ordinary non-secret data or files","D Compressing data before encryption to improve efficiency"], correct:2, explanation:"Steganography conceals the existence of a message by embedding it within another medium (image, audio, video, text) without visibly altering the carrier, used for covert communication or digital watermarking." },
  { id:30354, domain:3, level:2, question:"What does 'complete mediation' mean as a security design principle?", options:["A Every access request must go through an arbitration process involving multiple parties","B Access controls are mediated by a central policy enforcement point only once per session","C Security decisions require input from both the user and the system administrator","D Every access to every object must be checked against the access control policy every time"], correct:3, explanation:"Complete mediation requires that every access to every object be checked against the access control policy each time, preventing attacks that exploit cached or assumed permissions from a prior authorization check." },
  { id:30355, domain:3, level:2, question:"Which of the following best describes a covert channel?", options:["A A communication channel that violates security policy by transmitting information through unintended means","B A hidden network interface used to bypass firewall rules","C An encrypted communication channel used by insider threat actors","D A stealthy malware command-and-control mechanism using social media"], correct:0, explanation:"A covert channel is a communication path that was not intended for communication and violates security policy. Covert storage channels use storage objects; covert timing channels exploit shared system resources." },
  { id:30356, domain:3, level:2, question:"What is the purpose of key derivation functions (KDFs) like PBKDF2 or bcrypt?", options:["A Converting symmetric keys to asymmetric keys for hybrid encryption","B Distributing encryption keys securely across distributed systems","C Deriving cryptographic keys from passwords using intentional computational expense to slow attackers","D Generating asymmetric key pairs from random seed values"], correct:2, explanation:"KDFs derive cryptographic keys from passwords or passphrases, using salt and iterative hashing to make the derivation computationally expensive, significantly slowing brute-force and dictionary attacks." },
  { id:30357, domain:3, level:2, question:"What does the concept of 'fail secure' (fail safe) mean in system design?", options:["A Systems should automatically recover from failure without human intervention","B Redundant systems ensure no failure can occur during critical operations","C Security mechanisms remain active even during software updates","D When a system fails, it should default to a secure state denying access"], correct:3, explanation:"Fail secure (fail safe) means that when a system fails or encounters an error, it defaults to denying access or taking the most restrictive action, preventing failures from creating security vulnerabilities." },
  { id:30358, domain:3, level:2, question:"Which cryptographic primitive provides both confidentiality and integrity in a single operation?", options:["A Authenticated Encryption with Associated Data (AEAD)","B HMAC","C Diffie-Hellman key exchange","D RSA encryption"], correct:0, explanation:"AEAD modes (like AES-GCM or ChaCha20-Poly1305) provide confidentiality through encryption and authenticity/integrity through authentication tags in a single operation, preventing padding oracle and ciphertext tampering attacks." },
  { id:30359, domain:3, level:2, question:"What is the purpose of a digital signature?", options:["A To create a secure channel for key exchange between parties","B To authenticate the sender using a shared secret key","C To encrypt data so only the intended recipient can read it","D To provide non-repudiation and integrity verification using the sender's private key"], correct:3, explanation:"Digital signatures use the sender's private key to sign data, allowing recipients to verify integrity and non-repudiation (the sender cannot deny signing). The signature is verified using the sender's public key." },
  { id:30360, domain:3, level:2, question:"Which hashing algorithm produces a 256-bit output and is recommended for most security applications?", options:["A MD5","B SHA-256","C SHA-1","D CRC-32"], correct:1, explanation:"SHA-256 (part of the SHA-2 family) produces a 256-bit hash, is computationally secure against collision attacks, and is widely recommended for digital signatures, certificates, and data integrity verification." },
  { id:30361, domain:4, level:2, question:"What type of DNS attack involves poisoning the resolver cache with false records to redirect traffic?", options:["A DNS cache poisoning (DNS spoofing)","B DNS zone transfer exploit","C DNS tunneling attack","D DNS amplification attack"], correct:0, explanation:"DNS cache poisoning injects malicious DNS records into a resolver's cache, causing it to return incorrect IP addresses for domain names, redirecting users to attacker-controlled servers for phishing or malware distribution." },
  { id:30362, domain:4, level:2, question:"What is DNS Security Extensions (DNSSEC) designed to prevent?", options:["A DNS cache poisoning by providing cryptographic authentication of DNS responses","B Encrypted DNS queries from being intercepted by ISPs","C DNS amplification attacks by rate-limiting recursive queries","D Unauthorized zone transfers between DNS servers"], correct:0, explanation:"DNSSEC adds cryptographic signatures to DNS records, allowing resolvers to verify that responses are authentic and unmodified, preventing cache poisoning and man-in-the-middle attacks on DNS resolution." },
  { id:30363, domain:4, level:2, question:"Which network protocol uses both UDP and TCP on port 53?", options:["A HTTP","B DNS","C SMTP","D SNMP"], correct:1, explanation:"DNS uses UDP port 53 for standard queries (faster, lower overhead) and TCP port 53 for responses exceeding 512 bytes and zone transfers, which require reliable transmission." },
  { id:30364, domain:4, level:2, question:"What is the primary risk associated with using Telnet for remote server administration?", options:["A Telnet sessions cannot be terminated gracefully if the connection is lost","B Telnet does not support authentication mechanisms","C Telnet only supports IPv4 and not modern IPv6 networks","D Telnet transmits all data including credentials in cleartext"], correct:3, explanation:"Telnet transmits all data, including usernames and passwords, in plaintext without encryption. SSH should be used instead, as it provides encrypted authentication and session data." },
  { id:30365, domain:4, level:2, question:"What does the principle of network segmentation accomplish for security?", options:["A It ensures all traffic is inspected by an application-layer proxy","B It eliminates the need for perimeter firewalls in modern network designs","C It prevents all users from accessing the internet directly","D It limits lateral movement by containing breaches and restricting unnecessary inter-segment traffic"], correct:3, explanation:"Network segmentation divides networks into smaller segments, limiting the blast radius of a security incident by preventing attackers from freely moving laterally between systems once they compromise one segment." },
  { id:30366, domain:4, level:2, question:"Which technology creates virtual isolated network segments within a shared physical network infrastructure?", options:["A VPN (Virtual Private Network)","B VLAN (Virtual Local Area Network)","C DMZ (Demilitarized Zone)","D SDN (Software-Defined Networking)"], correct:1, explanation:"VLANs create logical network segments on shared physical infrastructure, controlling broadcast domains and implementing network segmentation without requiring separate physical hardware for each network segment." },
  { id:30367, domain:4, level:2, question:"What is the primary purpose of a demilitarized zone (DMZ) in network architecture?", options:["A To host public-facing services in a network segment isolated from both the internet and internal network","B To isolate administrator workstations from regular user networks","C To provide a buffer zone where all traffic is decrypted for inspection","D To segment wireless access points from wired infrastructure"], correct:0, explanation:"A DMZ is a network segment between the internet and the internal network that hosts public-facing servers (web, mail, DNS). It limits exposure so that if a public server is compromised, attackers don't have direct access to the internal network." },
  { id:30368, domain:4, level:2, question:"Which type of IDS/IPS detection method creates a baseline of normal behavior and alerts on deviations?", options:["A Anomaly-based (behavior-based) detection","B Rule-based detection","C Protocol-based detection","D Signature-based detection"], correct:0, explanation:"Anomaly-based detection establishes a baseline of normal network or system behavior and alerts when activity deviates significantly from that baseline, allowing detection of unknown or novel attacks but with higher false positive rates." },
  { id:30369, domain:4, level:2, question:"What is the main limitation of signature-based intrusion detection systems?", options:["A They cannot detect zero-day attacks or malware without a matching signature","B They can only monitor network traffic, not host-based activities","C They require dedicated hardware and cannot run as software solutions","D They generate too many false positives for practical deployment"], correct:0, explanation:"Signature-based IDS/IPS rely on known attack patterns (signatures) and cannot detect novel or zero-day attacks that don't match any existing signature in their database." },
  { id:30370, domain:4, level:2, question:"What is a 'sinkhole' in the context of network security?", options:["A A deep packet inspection system monitoring DNS queries","B A network device that absorbs and drops all inbound DDoS traffic","C A honeypot designed to attract and analyze botnet traffic","D A routing technique that redirects malicious traffic to a controlled destination for analysis"], correct:3, explanation:"DNS/route sinkholing redirects traffic destined for known malicious domains/IPs to a controlled server, preventing malware from reaching command-and-control servers and allowing analysis of infected systems." },
  { id:30371, domain:4, level:2, question:"What protocol does HTTPS use to secure web communications?", options:["A IPSec","B SFTP (Secure File Transfer Protocol)","C TLS (Transport Layer Security)","D SSH (Secure Shell)"], correct:2, explanation:"HTTPS uses TLS (formerly SSL) to encrypt HTTP communications, providing confidentiality, integrity, and server authentication (via certificates) for web traffic." },
  { id:30372, domain:4, level:2, question:"Which TLS component verifies the server's identity to the client?", options:["A The session key","B The client hello message","C The cipher suite negotiation","D The server's digital certificate"], correct:3, explanation:"The server's digital certificate (issued by a trusted Certificate Authority) contains the server's public key and identity information. Clients verify the certificate to authenticate the server before trusting the connection." },
  { id:30373, domain:4, level:2, question:"What is perfect forward secrecy (PFS) in TLS?", options:["A Ensuring all TLS versions support backward compatibility with older clients","B Using the same session key for all connections to improve efficiency","C Generating unique session keys so compromising the server's private key doesn't compromise past sessions","D Encrypting the TLS handshake to prevent traffic analysis"], correct:2, explanation:"PFS (using ephemeral Diffie-Hellman or ECDH key exchange) generates unique session keys for each connection. Even if the server's long-term private key is later compromised, past encrypted sessions cannot be decrypted." },
  { id:30374, domain:4, level:2, question:"Which network security technology monitors and filters web traffic based on content and URL categories?", options:["A Network-based IPS","B Secure Web Gateway (SWG)","C Next-generation firewall","D Email security gateway"], correct:1, explanation:"A Secure Web Gateway provides URL filtering, malware inspection, data loss prevention, and SSL inspection for outbound web traffic, enforcing acceptable use policies and blocking malicious content." },
  { id:30375, domain:4, level:2, question:"What type of attack uses multiple systems to overwhelm a target's resources with traffic?", options:["A Man-in-the-middle attack","B Distributed Denial of Service (DDoS) attack","C Cross-site request forgery attack","D Session hijacking attack"], correct:1, explanation:"DDoS attacks coordinate many compromised systems (botnet) to simultaneously flood a target with traffic or requests, exhausting bandwidth, processing capacity, or connections to render the service unavailable." },
  { id:30376, domain:5, level:2, question:"What is the purpose of a Password Authentication Protocol (PAP) replacement like CHAP?", options:["A To eliminate the need for password-based authentication entirely","B To avoid transmitting the actual password over the network by using challenge-response","C To encrypt all PAP authentication exchanges using TLS","D To allow users to authenticate with multiple passwords for redundancy"], correct:1, explanation:"CHAP (Challenge Handshake Authentication Protocol) uses a challenge-response mechanism where only a hash of the password is transmitted, not the password itself, preventing interception attacks that affect PAP." },
  { id:30377, domain:5, level:2, question:"What is the primary security benefit of using smart cards for authentication?", options:["A Smart cards are cheaper to deploy than password-based systems","B Smart cards provide two-factor authentication combining something you have with something you know","C Smart cards eliminate the need for a PKI infrastructure","D Smart cards cannot be replicated or duplicated under any circumstances"], correct:1, explanation:"Smart cards combine a physical card (something you have) with a PIN (something you know), providing two-factor authentication. The private key never leaves the card, preventing extraction attacks." },
  { id:30378, domain:5, level:2, question:"What does SCIM (System for Cross-domain Identity Management) provide?", options:["A Certificate-based authentication for mobile device management","B Encrypted transmission of identity attributes between identity providers","C Standardized API for automating user provisioning and deprovisioning across multiple systems","D Single sign-on capability for cloud-based applications"], correct:2, explanation:"SCIM is an open standard protocol that automates the exchange of user identity information between identity providers and service providers, standardizing user provisioning/deprovisioning to reduce administrative overhead." },
  { id:30379, domain:5, level:2, question:"Which concept limits the damage from a compromised account by ensuring it has only the minimum permissions needed?", options:["A Defense in depth","B Separation of duties","C Mandatory access control","D Principle of least privilege"], correct:3, explanation:"The principle of least privilege grants accounts, processes, and users only the minimum permissions required for their specific tasks, limiting the blast radius if credentials are compromised." },
  { id:30380, domain:5, level:2, question:"What is the difference between identification and authentication?", options:["A Identification claims an identity; authentication proves that the claimed identity is genuine","B Identification is performed by the server; authentication is performed by the client","C Identification uses passwords; authentication uses biometrics","D Identification is a one-time process; authentication occurs at every login"], correct:0, explanation:"Identification is the act of claiming an identity (e.g., entering a username). Authentication is the process of proving the claimed identity is genuine (e.g., providing a password, token, or biometric)." },
  { id:30381, domain:5, level:2, question:"What is the primary purpose of a centralized identity management system?", options:["A Automatically granting users all permissions needed for their department","B Providing faster authentication by caching credentials locally on each device","C Eliminating the need for access control policies across connected systems","D Managing user identities, access rights, and provisioning from a single authoritative source"], correct:3, explanation:"Centralized identity management provides a single authoritative source for user identities, roles, and access rights, simplifying provisioning/deprovisioning, ensuring consistency, and improving audit capabilities." },
  { id:30382, domain:5, level:2, question:"Which access control type uses rules defined by system administrators and cannot be changed by data owners?", options:["A Discretionary Access Control (DAC)","B Role-Based Access Control (RBAC)","C Mandatory Access Control (MAC)","D Attribute-Based Access Control (ABAC)"], correct:2, explanation:"In MAC, access control policies are set by administrators or the system based on security labels, and individual data owners cannot override these rules. This is commonly used in military/government environments." },
  { id:30383, domain:5, level:2, question:"What is OpenID Connect (OIDC) built on top of?", options:["A SAML 2.0 for identity federation","B OAuth 2.0, adding an identity layer for authentication","C Kerberos for distributed authentication","D LDAP for directory-based identity management"], correct:1, explanation:"OpenID Connect is an authentication layer built on top of OAuth 2.0. It adds an ID token (JWT) that contains user identity information, enabling both authentication and authorization in a single framework." },
  { id:30384, domain:5, level:2, question:"What is a common attack against Kerberos that involves requesting many service tickets to crack offline?", options:["A Pass-the-hash attack","B Golden ticket attack","C Silver ticket attack","D Kerberoasting attack"], correct:3, explanation:"Kerberoasting requests service tickets for SPNs, then attempts to crack them offline. Since service tickets are encrypted with the service account's password hash, weak passwords can be recovered without triggering online authentication failures." },
  { id:30385, domain:5, level:2, question:"What does a 'golden ticket' attack in Kerberos allow an attacker to do?", options:["A Forge Kerberos TGTs to impersonate any user, including administrators, by knowing the KRBTGT hash","B Bypass multi-factor authentication for privileged accounts","C Create fake X.509 certificates to impersonate servers","D Forge authentication cookies for any web application"], correct:0, explanation:"A golden ticket attack forges Ticket Granting Tickets using the compromised KRBTGT account hash, allowing the attacker to impersonate any user in the domain with any group membership, providing persistent domain-wide access." },
  { id:30386, domain:5, level:2, question:"Which authentication method involves verifying a user's identity based on behavioral patterns over time?", options:["A Multi-factor authentication","B Certificate-based authentication","C Continuous authentication (behavioral biometrics)","D Knowledge-based authentication"], correct:2, explanation:"Continuous authentication (behavioral biometrics) monitors patterns like typing cadence, mouse movements, and usage behavior throughout a session to continuously verify user identity, detecting session hijacking or account takeover." },
  { id:30387, domain:5, level:2, question:"What is the primary security issue with shared accounts (generic accounts)?", options:["A Shared accounts are more difficult to manage in Active Directory","B Shared accounts prevent individual accountability and complicate audit trails","C Shared accounts require more complex password policies to maintain","D Shared accounts are incompatible with most modern authentication protocols"], correct:1, explanation:"Shared accounts (e.g., 'admin' used by multiple people) break individual accountability. It's impossible to determine which individual performed specific actions, violating non-repudiation and making forensic investigation difficult." },
  { id:30388, domain:5, level:2, question:"What is a time-based one-time password (TOTP)?", options:["A A password that changes after a fixed number of authentication attempts","B A password valid only during business hours to limit unauthorized access","C A password generated from a shared secret and current time, valid only briefly","D A temporary password sent via SMS that expires after first use"], correct:2, explanation:"TOTP generates authentication codes from a shared secret combined with the current time (typically 30-second windows), producing short-lived codes that are valid only briefly, preventing replay attacks." },
  { id:30389, domain:5, level:2, question:"What is the primary advantage of FIDO2/WebAuthn for authentication?", options:["A It requires only a username without any additional factor","B It eliminates the need for any form of user verification","C It is backward compatible with all legacy password-based systems","D It provides phishing-resistant authentication using public key cryptography tied to the origin"], correct:3, explanation:"FIDO2/WebAuthn uses asymmetric cryptography where the private key never leaves the authenticator and the key is bound to the specific origin, making it resistant to phishing because credentials cannot be reused on fake sites." },
  { id:30390, domain:5, level:2, question:"What is account harvesting in the context of identity attacks?", options:["A Enumerating valid usernames through login error messages or timing differences","B Extracting all user accounts from a compromised directory service","C Collecting user credentials from phishing campaigns over time","D Aggregating identity information from multiple breached databases"], correct:0, explanation:"Account harvesting exploits authentication systems that reveal whether a username exists (through different error messages or response times), allowing attackers to enumerate valid accounts for targeted credential attacks." },
  { id:30391, domain:3, level:2, question:"What is the role of a Certificate Authority (CA) in a PKI?", options:["A To store all private keys for recovery purposes","B To issue, sign, and revoke digital certificates binding identities to public keys","C To encrypt all communications between clients and servers","D To manage access control policies for certificate holders"], correct:1, explanation:"A CA is a trusted third party that issues digital certificates, vouching for the binding between an entity's identity and its public key. The CA signs certificates with its own private key, allowing others to verify authenticity." },
  { id:30392, domain:3, level:2, question:"What is a Certificate Revocation List (CRL)?", options:["A A database of all certificates issued by a Certificate Authority","B A list of certificates pending issuance by a Certificate Authority","C A list of approved certificate algorithms and key lengths","D A list of certificates that have been revoked before their expiration date"], correct:3, explanation:"A CRL is a list published by a CA containing serial numbers of certificates that have been revoked (due to key compromise, personnel changes, etc.) before their scheduled expiration. Applications check CRLs to reject revoked certificates." },
  { id:30393, domain:3, level:2, question:"What advantage does OCSP (Online Certificate Status Protocol) provide over CRL?", options:["A OCSP provides better encryption than CRL-based verification","B OCSP eliminates the need for Certificate Authorities to revoke certificates","C OCSP allows certificates to be verified without network connectivity","D OCSP provides real-time certificate status without downloading large CRL files"], correct:3, explanation:"OCSP allows real-time certificate status checking by querying the CA's OCSP responder, avoiding the overhead of downloading potentially large CRL files and providing more timely revocation status." },
  { id:30394, domain:3, level:2, question:"What is the key escrow concept in cryptography?", options:["A Encrypting backup copies of keys with a secondary key pair","B Storing encryption keys in a physically secure hardware vault","C Temporary transfer of encryption keys to a trusted third party for lawful access","D Splitting keys between multiple administrators using secret sharing"], correct:2, explanation:"Key escrow involves depositing copies of encryption keys with a trusted third party (often a government agency or compliance officer) so that encrypted data can be accessed under lawful authority or for business continuity purposes." },
  { id:30395, domain:3, level:2, question:"What does 'security through obscurity' mean and why is it considered a weak security strategy?", options:["A Using complex encryption algorithms that attackers find difficult to understand","B Relying on secrecy of design or implementation as the primary security mechanism, which fails when secrets are exposed","C Hiding systems behind network address translation to obscure their true addresses","D Limiting public documentation about security controls to prevent enumeration"], correct:1, explanation:"Security through obscurity relies on keeping system design, vulnerabilities, or configurations secret. It is weak because once the secret is discovered (through reverse engineering, leaks, or research), all security disappears. Defense should not depend on obscurity." },
  { id:30396, domain:3, level:2, question:"What is the Diffie-Hellman protocol used for?", options:["A Providing certificate-based authentication in PKI environments","B Securely establishing a shared secret key over an untrusted channel","C Generating and verifying digital signatures for message authentication","D Encrypting messages using asymmetric public key encryption"], correct:1, explanation:"Diffie-Hellman allows two parties to establish a shared secret key over an insecure channel without previously sharing any secret information, by exchanging public values and computing a common secret from their private values." },
  { id:30397, domain:4, level:2, question:"What is 'network access control' (NAC)?", options:["A Enforcing security policy compliance before granting devices access to the network","B Filtering network traffic based on application-layer content inspection","C Managing network administrator credentials for device configuration","D Controlling user access to specific network resources based on roles"], correct:0, explanation:"NAC evaluates endpoint compliance (patches, AV, configuration) before granting network access, quarantining non-compliant devices, ensuring only healthy and policy-compliant devices connect to the network." },
  { id:30398, domain:4, level:2, question:"What is the primary security risk of BYOD (Bring Your Own Device) policies?", options:["A Personal devices are typically slower than corporate devices","B BYOD increases helpdesk costs for device support","C Personal devices may not meet corporate security standards and can introduce vulnerabilities","D Personal devices are incompatible with enterprise authentication protocols"], correct:2, explanation:"BYOD introduces risks including unpatched personal devices, mixing personal and corporate data, difficulty enforcing security policies, and challenges with device management and remote wipe of corporate data." },
  { id:30399, domain:4, level:2, question:"What does a next-generation firewall (NGFW) provide beyond traditional stateful inspection?", options:["A Hardware-accelerated encryption for all network traffic","B Automated vulnerability scanning of connected network devices","C Physical port security and MAC address filtering for endpoints","D Application awareness, user identity integration, and deep packet inspection capabilities"], correct:3, explanation:"NGFWs provide traditional stateful inspection plus application-layer (Layer 7) awareness, user identity integration, SSL/TLS inspection, IPS capabilities, and threat intelligence feeds, enabling policy enforcement based on applications and users." },
  { id:30400, domain:4, level:2, question:"What security mechanism does 802.1AE (MACsec) provide?", options:["A Wireless network encryption for enterprise Wi-Fi deployments","B Layer 2 encryption and authentication for wired Ethernet frames","C Multi-factor authentication for network device access","D Encrypted tunneling for site-to-site VPN connections"], correct:1, explanation:"MACsec (802.1AE) provides hop-by-hop encryption and authentication at Layer 2 (Ethernet), securing traffic between directly connected devices and protecting against eavesdropping and tampering on local network segments." },
  { id:30401, domain:5, level:2, question:"What is an access control matrix?", options:["A A visual representation of physical access zones in a facility","B A table mapping subjects to objects with associated permissions","C A risk scoring system for privilege escalation attempts","D A cryptographic structure for managing certificate hierarchies"], correct:1, explanation:"An access control matrix is a conceptual model representing relationships between subjects (users, processes) and objects (files, resources), with each cell containing the permissions the subject has on the object." },
  { id:30402, domain:5, level:2, question:"What is the security benefit of account lockout policies?", options:["A They alert administrators when users attempt to log in after hours","B They reduce the number of passwords users need to remember","C They enforce password complexity requirements automatically","D They prevent brute-force attacks by locking accounts after repeated failed authentication attempts"], correct:3, explanation:"Account lockout policies lock user accounts after a configurable number of failed login attempts, preventing brute-force and password spraying attacks by limiting how many password guesses an attacker can make." },
  { id:30403, domain:5, level:2, question:"What is the primary purpose of a privileged identity management (PIM) solution?", options:["A Managing regular user account passwords across enterprise applications","B Governing elevated access rights, including just-in-time provisioning and approval workflows","C Monitoring network traffic for signs of privileged account compromise","D Providing multi-factor authentication for service accounts"], correct:1, explanation:"PIM solutions manage and govern privileged accounts through access request workflows, approval processes, time-limited access, session recording, and risk-based policies to enforce least-privilege for elevated access." },
  { id:30404, domain:5, level:2, question:"What type of attack involves stealing a user's session token to impersonate them?", options:["A Credential stuffing attack","B Session hijacking attack","C Privilege escalation attack","D Man-in-the-browser attack"], correct:1, explanation:"Session hijacking steals a valid session token (via XSS, network sniffing, or prediction) to impersonate the authenticated user, bypassing authentication since the server trusts the token." },
  { id:30405, domain:5, level:2, question:"What does 'account correlation' mean in identity governance?", options:["A Linking multiple user accounts belonging to the same individual across different systems","B Comparing account permissions to detect unauthorized privilege escalation","C Synchronizing account policies across all enterprise systems","D Associating user behavior analytics with specific account activities"], correct:0, explanation:"Account correlation links multiple accounts (Active Directory, cloud, application) that belong to the same individual, enabling centralized governance, unified access reviews, and complete visibility of an individual's total access." },
  { id:30406, domain:3, level:2, question:"What is the primary purpose of a security information and event management (SIEM) system?", options:["A Encrypting sensitive data stored across enterprise systems","B Blocking malicious network traffic at the perimeter","C Aggregating and correlating security events from multiple sources for centralized monitoring and analysis","D Managing patch deployment across all endpoints in the environment"], correct:2, explanation:"SIEM systems collect logs and security events from across the environment, correlate them to detect patterns, generate alerts, and support compliance reporting and incident investigation." },
  { id:30407, domain:3, level:2, question:"What does the concept of 'defense in depth' imply for security architecture?", options:["A Using the most expensive security controls available for critical assets","B Ensuring all security functions are performed by a single integrated platform","C Focusing all security investment on perimeter defenses to prevent breaches","D Implementing multiple layers of security controls so that the failure of one doesn't compromise the whole system"], correct:3, explanation:"Defense in depth uses multiple independent security layers (perimeter, network, host, application, data) so that an attacker must defeat several controls, and failure of one layer doesn't mean complete compromise." },
  { id:30408, domain:3, level:2, question:"What is a security baseline in the context of system hardening?", options:["A The initial state of a system before any security controls are applied","B A performance benchmark for measuring security tool effectiveness","C The minimum acceptable security configuration for a particular system type","D The maximum security configuration achievable for a given platform"], correct:2, explanation:"A security baseline defines the minimum required security configuration (e.g., enabled controls, disabled services, patches applied) for a system type, ensuring consistent protection across similar systems in the environment." },
  { id:30409, domain:3, level:2, question:"What is a supply chain attack in software security?", options:["A An attack targeting manufacturing facilities to disrupt product delivery","B Compromising a trusted third-party component or vendor to distribute malicious code to downstream targets","C A social engineering attack targeting employees in procurement roles","D A denial of service attack against logistics and ordering systems"], correct:1, explanation:"Supply chain attacks compromise software dependencies, build systems, update mechanisms, or vendors to inject malicious code that is then distributed to many downstream customers who trust the compromised component." },
  { id:30410, domain:3, level:2, question:"What is the purpose of code signing?", options:["A Verifying software authenticity and integrity using the developer's digital signature","B Documenting code authorship for legal liability purposes","C Obfuscating compiled code to prevent reverse engineering","D Encrypting source code to prevent intellectual property theft"], correct:0, explanation:"Code signing uses the developer's private key to sign software, allowing users to verify that code is from a trusted source and hasn't been tampered with since signing, preventing installation of malicious or modified software." },
  { id:30411, domain:3, level:2, question:"What is a side-channel attack?", options:["A An attack exploiting a secondary communication channel in a protocol implementation","B An attack deriving secret information from physical implementation characteristics like power consumption or timing","C An attack targeting backup systems when primary systems are hardened","D An attack using social engineering alongside technical exploitation"], correct:1, explanation:"Side-channel attacks exploit information leaked through physical implementation (power consumption, electromagnetic emissions, timing, sound) rather than weaknesses in the algorithm itself, circumventing mathematical security guarantees." },
  { id:30412, domain:3, level:2, question:"What does the principle of psychological acceptability require?", options:["A Security training should be designed to be memorable and engaging","B Users should understand and accept the rationale behind security policies","C Security mechanisms should not make resources more difficult to access than without them","D Security awareness programs should address cognitive biases in users"], correct:2, explanation:"Psychological acceptability requires that security mechanisms not create excessive burden, as users will work around controls they find too difficult to use. Usable security leads to better compliance." },
  { id:30413, domain:3, level:2, question:"What is fuzzing in software security testing?", options:["A Providing malformed or unexpected inputs to an application to discover vulnerabilities","B Testing security controls under high-load conditions to identify performance issues","C Obfuscating code to test if reverse engineering tools can analyze it","D Reviewing code logic by simulating the thought process of an attacker"], correct:0, explanation:"Fuzzing (fuzz testing) sends random, malformed, or unexpected inputs to an application to discover crashes, hangs, memory leaks, and security vulnerabilities like buffer overflows or injection flaws that proper input validation would prevent." },
  { id:30414, domain:4, level:2, question:"What is the purpose of out-of-band network management?", options:["A Managing network devices using encrypted in-band protocols","B Monitoring network traffic without impacting production bandwidth","C Providing redundant network paths for critical management traffic","D Using a separate management network isolated from production traffic for device administration"], correct:3, explanation:"Out-of-band management uses a separate, dedicated network for managing infrastructure devices, ensuring administrators can access devices for troubleshooting even when production networks are down or compromised." },
  { id:30415, domain:4, level:2, question:"What is a packet-filtering firewall's primary limitation compared to stateful inspection firewalls?", options:["A Packet filters cannot inspect UDP traffic","B Packet filters examine each packet independently without tracking connection state","C Packet filters are unable to handle high traffic volumes","D Packet filters cannot be configured with deny rules"], correct:1, explanation:"Packet filters evaluate each packet independently against rules but don't track connection state. Stateful firewalls maintain a connection table, allowing them to distinguish valid response packets from unsolicited inbound packets." },
  { id:30416, domain:4, level:2, question:"What does a content delivery network (CDN) provide as a security benefit?", options:["A Vulnerability scanning of web application source code","B End-to-end encryption between clients and origin servers","C DDoS mitigation by absorbing and distributing attack traffic across many edge locations","D Certificate management for all hosted domains automatically"], correct:2, explanation:"CDNs distribute content across many edge nodes globally, which helps absorb DDoS attacks by distributing the attack traffic and providing scrubbing capabilities, protecting origin servers from volumetric attacks." },
  { id:30417, domain:4, level:2, question:"Which protocol is used for sending email and is vulnerable to spoofing without additional authentication controls?", options:["A IMAP","B SMTP","C POP3","D MIME"], correct:1, explanation:"SMTP (Simple Mail Transfer Protocol) lacks built-in sender authentication, making it susceptible to spoofing. SPF, DKIM, and DMARC are additional mechanisms layered on top of SMTP to authenticate senders." },
  { id:30418, domain:4, level:2, question:"What is DMARC and what does it enforce?", options:["A A DNS security extension for protecting email server records","B A network monitoring protocol that reports on traffic anomalies","C A firewall policy standard for filtering malicious email attachments","D An email authentication framework that specifies how to handle emails failing SPF or DKIM checks"], correct:3, explanation:"DMARC (Domain-based Message Authentication, Reporting & Conformance) builds on SPF and DKIM, letting domain owners specify how receiving mail servers should handle emails that fail authentication (none, quarantine, or reject)." },
  { id:30419, domain:4, level:2, question:"What type of malware hides itself by modifying the OS to conceal its presence?", options:["A Spyware","B Adware","C Rootkit","D Ransomware"], correct:2, explanation:"Rootkits modify the operating system kernel or other low-level components to hide their presence from security tools, system administrators, and antivirus software, making detection and removal extremely difficult." },
  { id:30420, domain:4, level:2, question:"What is network traffic analysis (NTA) used for in security monitoring?", options:["A Encrypting all network communications for confidentiality","B Managing network device configurations and firmware updates","C Detecting anomalies and threats by analyzing network flow data and packet content","D Optimizing network bandwidth allocation for critical applications"], correct:2, explanation:"NTA analyzes network flow metadata (NetFlow, IPFIX) and packet data to detect threats like lateral movement, data exfiltration, C2 communications, and other anomalous behaviors that indicate compromise." },
  { id:30421, domain:5, level:2, question:"What is a credential stuffing attack?", options:["A Injecting malicious credentials into authentication databases","B Brute-forcing passwords by trying all possible combinations","C Using stolen username/password pairs from one breach to authenticate to other services","D Social engineering users into revealing their login credentials"], correct:2, explanation:"Credential stuffing uses large lists of username/password combinations from data breaches to attempt login to other services, exploiting password reuse. Multi-factor authentication is the most effective defense." },
  { id:30422, domain:5, level:2, question:"What is the purpose of password salting?", options:["A Adding extra characters to make passwords longer and more complex","B Encrypting stored passwords with a system-wide encryption key","C Rotating passwords automatically after a configured time period","D Adding a unique random value to each password before hashing to prevent rainbow table attacks"], correct:3, explanation:"A salt is a unique random value added to each password before hashing, ensuring that identical passwords produce different hashes, defeating precomputed rainbow tables and making parallel cracking attacks more expensive." },
  { id:30423, domain:5, level:2, question:"What does non-repudiation in information security ensure?", options:["A That system availability is maintained during security incidents","B That all communications are encrypted to prevent eavesdropping","C That a party cannot deny having performed a specific action or sent a specific message","D That access control decisions cannot be appealed by users"], correct:2, explanation:"Non-repudiation ensures that a party cannot deny performing an action (e.g., sending a message, approving a transaction). Digital signatures provide non-repudiation by binding the signer's private key to the signed data." },
  { id:30424, domain:5, level:2, question:"What is the primary purpose of a single sign-on (SSO) system?", options:["A Allowing users to authenticate once and access multiple systems without re-entering credentials","B Requiring users to authenticate separately to each system for maximum security","C Centralizing all user passwords in a single encrypted vault","D Eliminating the need for passwords by using biometric authentication only"], correct:0, explanation:"SSO allows users to authenticate once and seamlessly access multiple connected systems, improving user experience while centralizing authentication, simplifying management, and enabling consistent security policy enforcement." },
  { id:30425, domain:5, level:2, question:"What is the security principle of 'need to know'?", options:["A Users should know their security clearance level and restrictions","B Security teams need complete visibility into all user activities","C Access to information should be limited to those who require it for their specific job function","D Management needs to be informed of all security incidents immediately"], correct:2, explanation:"Need to know limits information access to individuals who require that specific information to perform their job duties, complementing MAC clearance requirements to ensure that cleared individuals only access relevant information." },
  { id:30426, domain:5, level:2, question:"What is an account takeover (ATO) attack?", options:["A An attacker creating new accounts in a target system","B Elevating privileges within a compromised system account","C Transferring account ownership through social engineering of IT administrators","D Gaining unauthorized control of a legitimate user's account through various credential theft techniques"], correct:3, explanation:"Account takeover involves illegitimately gaining access to a user's account using stolen credentials, session tokens, SIM swapping, or other techniques, allowing attackers to impersonate the victim and abuse their access." },
  { id:30427, domain:5, level:2, question:"What does user and entity behavior analytics (UEBA) detect?", options:["A Anomalous user and system behavior that may indicate insider threats or compromised accounts","B Network intrusions at the perimeter firewall level","C Malware signatures in files and email attachments","D Unauthorized software installations on managed endpoints"], correct:0, explanation:"UEBA establishes behavioral baselines for users and entities, then detects deviations that may indicate insider threats, compromised accounts, or data exfiltration attempts, providing context that signature-based tools miss." },
  { id:30428, domain:3, level:2, question:"What does isolation in virtualization security mean?", options:["A Ensuring that virtual machines cannot directly access each other's memory or resources","B Separating development and production environments into different hypervisors","C Preventing virtual machines from accessing external networks","D Running virtual machines only on dedicated physical hardware"], correct:0, explanation:"VM isolation ensures that virtual machines are logically separated, preventing one VM from reading or modifying another VM's memory, storage, or CPU state, even when sharing physical hardware resources." },
  { id:30429, domain:3, level:2, question:"What is a hypervisor's role in virtual machine security?", options:["A Encrypting all data stored on virtual machine disk images","B Managing and isolating virtual machines, controlling access to physical hardware resources","C Providing network security between virtual machines in the same host","D Monitoring virtual machine processes for malicious behavior"], correct:1, explanation:"The hypervisor (VMM) creates and manages virtual machines, enforcing isolation between them by mediating access to physical resources (CPU, memory, I/O). Its security is critical since a compromised hypervisor threatens all hosted VMs." },
  { id:30430, domain:3, level:2, question:"What is VM escape and why is it a critical security concern?", options:["A An attacker breaking out of a virtual machine to access the hypervisor or other VMs","B A VM unexpectedly shutting down and freeing its resources to the host","C A VM migrating to another physical host without authorization","D A vulnerability allowing VMs to consume more resources than allocated"], correct:0, explanation:"VM escape is a critical vulnerability where malicious code in a guest VM breaks out of its isolation to execute on the hypervisor or access other VMs, potentially compromising the entire physical host and all its virtual machines." },
  { id:30431, domain:3, level:2, question:"What is a container security concern compared to virtual machines?", options:["A Containers are less portable than virtual machines","B Containers use more resources than equivalent virtual machines","C Containers cannot be monitored by security tools","D Containers share the host OS kernel, so a kernel vulnerability could affect all containers on the host"], correct:3, explanation:"Unlike VMs with separate kernels, containers share the host OS kernel. A kernel-level vulnerability exploited in one container could potentially escape to the host or other containers, creating a larger blast radius than VM-based isolation." },
  { id:30432, domain:3, level:2, question:"What is the purpose of secure boot?", options:["A Ensuring that only cryptographically signed and trusted software loads during the boot process","B Authenticating users before the operating system initializes","C Preventing physical access attacks by locking the boot sequence","D Encrypting the hard drive before the operating system loads"], correct:0, explanation:"Secure boot verifies the digital signatures of each piece of boot software (UEFI firmware, bootloader, OS kernel) against a trusted database, ensuring that only authorized, unmodified software runs during system startup." },
  { id:30433, domain:3, level:2, question:"What is data masking used for in development and testing environments?", options:["A Encrypting production data before storing it in backups","B Replacing sensitive data with realistic but fictitious values to protect privacy in non-production use","C Hiding sensitive fields from unauthorized users in production applications","D Anonymizing audit logs before archiving them for long-term retention"], correct:1, explanation:"Data masking (data obfuscation) replaces sensitive production data (SSNs, credit cards, medical records) with realistic but fake values for use in development and testing, preventing unauthorized exposure of real sensitive data." },
  { id:30434, domain:3, level:2, question:"What is a Faraday cage used for in physical security?", options:["A Creating an electromagnetic barrier that blocks wireless signals from entering or leaving","B Providing a secure storage area for classified documents","C Preventing physical intrusion into sensitive equipment areas","D Protecting electrical equipment from power surges and lightning"], correct:0, explanation:"A Faraday cage is an enclosure made of conductive material that blocks electromagnetic fields. In security, it prevents wireless signals (Wi-Fi, cellular, RFID) from entering or leaving a space, protecting against wireless eavesdropping or electronic surveillance." },
  { id:30435, domain:4, level:2, question:"What does egress filtering accomplish in network security?", options:["A Inspecting and filtering outbound traffic to prevent data exfiltration and limit attack capabilities","B Blocking unsolicited inbound traffic from reaching internal systems","C Monitoring all outbound connections for compliance reporting purposes","D Authenticating outbound connection requests from internal users"], correct:0, explanation:"Egress filtering controls outbound traffic from the internal network, preventing data exfiltration, blocking outbound connections to malicious IPs, and limiting the damage attackers can do from inside a compromised network." },
  { id:30436, domain:4, level:2, question:"What is a honeynet?", options:["A A collection of threat intelligence feeds from honeypot data globally","B A network of honeypot systems designed to attract and study attackers","C A deception technology for redirecting attackers from real systems","D A network monitoring system using baited lures for intrusion detection"], correct:1, explanation:"A honeynet is a network of honeypot systems designed to look like a real network to attract attackers. It provides a controlled environment to observe attacker behavior, tactics, and tools without risking production systems." },
  { id:30437, domain:4, level:2, question:"What is a SIEM's correlation rule primarily used for?", options:["A Encrypting log data before storage to protect sensitive information","B Automatically remediating detected threats without human intervention","C Identifying patterns across multiple events that indicate a security incident","D Filtering out low-priority events to reduce analyst workload"], correct:2, explanation:"SIEM correlation rules analyze sequences or combinations of events across multiple sources to identify patterns that individually might be innocuous but together indicate a security incident, like failed logins followed by a successful login from a different location." },
  { id:30438, domain:4, level:2, question:"What is a web application firewall (WAF) designed to protect against?", options:["A Network-layer DDoS attacks targeting server bandwidth","B Unauthorized access to network infrastructure devices","C Application-layer attacks such as SQL injection, XSS, and CSRF targeting web applications","D Malware propagation through email and file sharing"], correct:2, explanation:"WAFs inspect HTTP/HTTPS traffic to detect and block application-layer attacks (OWASP Top 10) targeting web applications, including SQL injection, cross-site scripting, CSRF, and other web-specific vulnerabilities." },
  { id:30439, domain:4, level:2, question:"What is the purpose of a security orchestration, automation, and response (SOAR) platform?", options:["A Replacing security analysts with automated systems","B Automating repetitive security tasks and coordinating incident response workflows","C Providing threat intelligence from external feeds automatically","D Monitoring cloud environments without manual configuration"], correct:1, explanation:"SOAR platforms automate repetitive security tasks (phishing analysis, IoC enrichment, account isolation), orchestrate tools across the security stack, and manage incident response workflows, allowing analysts to focus on complex investigations." },
  { id:30440, domain:4, level:2, question:"What does micro-segmentation accomplish that traditional VLANs cannot?", options:["A Authenticating each network packet against a policy database","B Providing encryption between all network segments","C Replacing physical network hardware with software-defined controls","D Enforcing granular east-west traffic controls between individual workloads in the same network segment"], correct:3, explanation:"Micro-segmentation applies granular security policies to individual workloads or applications (not just network segments), controlling east-west traffic between systems in the same VLAN and limiting lateral movement within a segment." },
  { id:30441, domain:5, level:2, question:"What is identity proofing?", options:["A Testing identity management systems for vulnerabilities","B Proving that two identity systems contain consistent information","C Verifying that a person claiming an identity is actually that person during account creation","D Auditing identity management processes for compliance certification"], correct:2, explanation:"Identity proofing verifies the real-world identity of a person before issuing them credentials. It may involve checking government IDs, knowledge-based questions, or in-person verification, ensuring accounts are issued to the right individuals." },
  { id:30442, domain:5, level:2, question:"What is a service account and what special security considerations apply?", options:["A An account used by applications or services with non-expiring credentials requiring tight monitoring","B A shared account used by multiple services with no special security requirements","C A temporary account created for specific service requests","D An external vendor account with limited access to internal systems"], correct:0, explanation:"Service accounts are used by applications and automated processes. They often have elevated privileges, non-expiring passwords, and are difficult to protect with MFA, requiring special controls like managed service accounts, regular audits, and PAM integration." },
  { id:30443, domain:5, level:2, question:"What does the 'principle of least privilege' require when a user changes job roles?", options:["A Previous role access should be revoked and only new role-appropriate access granted","B Access reviews should be conducted annually regardless of role changes","C The user's previous access is kept temporarily in case their new role requires it","D Management approval is required before any access change takes effect"], correct:0, explanation:"When roles change, least privilege requires promptly revoking old-role access and granting only new-role-required access. Keeping old access leads to privilege accumulation (access creep), violating least privilege principles." },
  { id:30444, domain:5, level:2, question:"What is a token-based authentication system?", options:["A A system requiring physical hardware tokens for all authentication","B A system using one-time passwords delivered via SMS","C A biometric authentication system using behavioral tokens","D A system where after initial authentication, an access token is issued to represent the authenticated session"], correct:3, explanation:"Token-based authentication issues an access token (e.g., JWT) after successful authentication. The token is presented for subsequent requests, eliminating the need to re-authenticate with credentials for each request." },
  { id:30445, domain:5, level:2, question:"What is the security risk of excessive privilege accumulation (privilege creep)?", options:["A Users become confused by having too many access options","B Privilege accumulation increases licensing costs for access management tools","C Excess privileges cause performance issues in directory services","D Users accumulate more permissions than needed over time, violating least privilege and increasing insider threat risk"], correct:3, explanation:"Privilege creep occurs when users accumulate permissions over time through role changes without revoking old access. This violates least privilege and increases risk by giving users far more access than their current job requires." },
  { id:30446, domain:5, level:2, question:"What is the purpose of an identity governance and administration (IGA) system?", options:["A Monitoring for unauthorized account activity in real time","B Enforcing password policies across all connected systems","C Providing authentication services for cloud applications","D Managing the full identity lifecycle including provisioning, access reviews, and policy enforcement"], correct:3, explanation:"IGA systems manage the complete identity lifecycle—account creation, role assignments, access certifications, segregation of duties enforcement, and deprovisioning—providing governance and audit capabilities for access management." },
  { id:30447, domain:5, level:2, question:"What type of access control model allows data owners to control access to their own resources?", options:["A Discretionary Access Control (DAC)","B Mandatory Access Control (MAC)","C Role-Based Access Control (RBAC)","D Rule-Based Access Control"], correct:0, explanation:"In DAC, data owners have discretion to grant or revoke access to their resources. File system ACLs in Windows and UNIX implement DAC, allowing file owners to set permissions independently." },
  { id:30448, domain:5, level:2, question:"What is the purpose of multi-factor authentication (MFA)?", options:["A To make the login process more difficult for all users","B To eliminate the need for passwords in enterprise environments","C To require proof of identity from multiple independent factor categories, increasing security","D To comply with specific regulatory requirements for authentication"], correct:2, explanation:"MFA requires users to present multiple authentication factors from different categories (knowledge, possession, inherence), so that compromising one factor (e.g., password) alone is insufficient to gain access." },
  { id:30449, domain:5, level:2, question:"What is password spraying and how does it differ from brute force?", options:["A Password spraying tries many passwords against one account; brute force tries one password against many","B Password spraying uses dictionary attacks; brute force uses purely random combinations","C Password spraying tries a few common passwords against many accounts to evade lockout thresholds","D Password spraying targets privileged accounts; brute force targets all account types"], correct:2, explanation:"Password spraying tries a few commonly used passwords against a large number of accounts, staying below lockout thresholds. Traditional brute force exhausts all combinations against a single target account, typically triggering lockout." },
  { id:30450, domain:5, level:2, question:"What is an entitlement review and why is it important for security compliance?", options:["A A review of system vulnerabilities to prioritize remediation efforts","B A technical scan of systems to discover unauthorized software installations","C An audit of authentication logs to detect unauthorized login attempts","D A periodic review of user access rights to verify they are still appropriate and necessary"], correct:3, explanation:"Entitlement reviews (access certifications) have managers or data owners periodically confirm that user access rights remain appropriate, detecting access creep, orphaned accounts, and excessive permissions to maintain least privilege." },
  { id:30451, domain:6, level:2, question:"What is the primary objective of a security assessment?", options:["A Implementing new security controls across the organization","B Documenting all security policies and procedures for audit purposes","C Evaluating the effectiveness of existing security controls against defined requirements","D Training staff on security awareness and best practices"], correct:2, explanation:"Security assessments evaluate the effectiveness of existing controls, identify vulnerabilities and gaps, and provide recommendations for improvement, forming a baseline for security program maturity." },
  { id:30452, domain:6, level:2, question:"What is the difference between a vulnerability assessment and a penetration test?", options:["A Vulnerability assessments identify weaknesses; penetration tests actively exploit them to demonstrate impact","B Vulnerability assessments are more expensive than penetration tests","C Penetration tests only cover external network perimeters; vulnerability assessments cover all assets","D Vulnerability assessments require elevated access; penetration tests are always done externally"], correct:0, explanation:"Vulnerability assessments identify and classify potential weaknesses without exploiting them. Penetration tests go further by actively exploiting vulnerabilities to demonstrate real-world impact, simulating actual attacker techniques." },
  { id:30453, domain:6, level:2, question:"What is a 'black box' penetration test?", options:["A A test where testers have no prior knowledge of the target environment","B A test focused on physical security and hardware tampering","C A test conducted without any documentation or scope agreement","D A test using only automated scanning tools without manual analysis"], correct:0, explanation:"In a black box test, testers have no advance knowledge of the target (like external attackers), simulating real-world scenarios. White box tests provide full access and knowledge; gray box provides partial information." },
  { id:30454, domain:6, level:2, question:"What does CVSS (Common Vulnerability Scoring System) measure?", options:["A The financial impact of exploiting a specific vulnerability","B The severity and characteristics of vulnerabilities using standardized numerical scores","C The probability that a specific vulnerability will be exploited in the wild","D The technical complexity of remediating a discovered vulnerability"], correct:1, explanation:"CVSS provides a standardized way to assess vulnerability severity (0-10 scale) based on exploitability metrics, impact metrics, and environmental factors, enabling consistent prioritization of remediation efforts." },
  { id:30455, domain:6, level:2, question:"What is the purpose of log management in security operations?", options:["A Reducing storage costs by archiving data more efficiently","B Monitoring system performance metrics to detect hardware failures","C Collecting, storing, and analyzing audit trails to support incident investigation and compliance","D Automating the deployment of security patches across systems"], correct:2, explanation:"Log management provides the audit trail needed for incident investigation, forensic analysis, compliance reporting, and threat detection. Logs must be collected centrally, protected from tampering, retained appropriately, and reviewed regularly." },
  { id:30456, domain:6, level:2, question:"What is a security audit's primary distinction from a security assessment?", options:["A Audits evaluate compliance with specific standards, policies, or regulations; assessments evaluate overall security posture","B Audits are performed by external parties; assessments are always internal","C Audits focus on technical controls; assessments focus on administrative controls","D Audits are one-time events; assessments are continuous monitoring processes"], correct:0, explanation:"Security audits measure compliance against defined requirements (standards, policies, regulations like PCI-DSS, HIPAA). Security assessments more broadly evaluate the overall security program effectiveness and risk posture." },
  { id:30457, domain:6, level:2, question:"What is static application security testing (SAST)?", options:["A Testing applications by sending them controlled inputs and observing outputs","B Analyzing application source code or binaries for vulnerabilities without executing the code","C Scanning running applications in production for real-time threats","D Testing application behavior under simulated attack conditions"], correct:1, explanation:"SAST analyzes source code, bytecode, or binaries at rest to find vulnerabilities (injection flaws, hardcoded credentials, buffer overflows) without executing the application, enabling early detection in the development lifecycle." },
  { id:30458, domain:6, level:2, question:"What is dynamic application security testing (DAST)?", options:["A Reviewing application source code manually for security flaws","B Scanning application dependencies for known vulnerable libraries","C Comparing application behavior against a secure baseline configuration","D Testing running applications by sending inputs and analyzing responses to find runtime vulnerabilities"], correct:3, explanation:"DAST tests applications while they are running by sending various inputs and analyzing responses, finding vulnerabilities like XSS, SQL injection, and authentication flaws that manifest at runtime, without needing source code access." },
  { id:30459, domain:6, level:2, question:"What does the term 'attack surface' refer to?", options:["A The sum of all points where an attacker could try to enter or extract data from a system","B The physical area of a facility vulnerable to intrusion","C The number of known vulnerabilities in a given system","D The network perimeter exposed to the internet"], correct:0, explanation:"The attack surface encompasses all possible points of entry or exploitation: exposed interfaces, services, protocols, user inputs, and code paths. Reducing the attack surface (disabling unused features, ports, services) reduces risk." },
  { id:30460, domain:6, level:2, question:"What is the purpose of a bug bounty program?", options:["A Inviting external security researchers to discover and report vulnerabilities in exchange for recognition or payment","B Rewarding employees for reporting internal policy violations","C Compensating vendors for patching vulnerabilities in their products","D Funding internal security research teams for vulnerability research"], correct:0, explanation:"Bug bounty programs invite independent security researchers to find and responsibly disclose vulnerabilities in exchange for rewards. They extend the organization's security testing capabilities beyond internal teams." },
  { id:30461, domain:6, level:2, question:"What is a security control gap analysis?", options:["A Testing security controls to verify they function as designed","B Comparing current security controls against a target state or standard to identify missing controls","C Documenting all existing security controls for compliance reporting","D Measuring the performance of security controls against defined metrics"], correct:1, explanation:"Gap analysis compares the current security control implementation against a target framework (ISO 27001, NIST CSF, SOC 2) to identify missing or insufficient controls requiring attention." },
  { id:30462, domain:6, level:2, question:"What is the primary purpose of penetration test rules of engagement?", options:["A Defining the technical tools allowed during testing","B Establishing boundaries, scope, authorization, and emergency contacts for the engagement","C Specifying the deliverables and reporting format required","D Determining the compensation structure for the testing team"], correct:1, explanation:"Rules of engagement define the legal authorization, scope (what's in/out of scope), testing windows, prohibited techniques, emergency escalation procedures, and communication protocols, protecting both the organization and testers." },
  { id:30463, domain:6, level:2, question:"What does SOC 2 Type II attestation report evaluate?", options:["A The design of security controls at a single point in time","B The operating effectiveness of controls over a defined audit period of several months","C Financial controls and accounting practices of service organizations","D Compliance with specific government security requirements"], correct:1, explanation:"SOC 2 Type II reports evaluate whether security controls were not only suitably designed but also operating effectively over a review period (typically 6-12 months), providing stronger assurance than Type I design reviews." },
  { id:30464, domain:6, level:2, question:"What is the OWASP Top 10?", options:["A A regularly updated list of the most critical web application security risks","B A list of the ten most dangerous malware families","C The ten most important security principles for software development","D A ranking of the top ten most common network vulnerabilities"], correct:0, explanation:"OWASP Top 10 is a consensus list of the most critical web application security risks (injection, broken authentication, XSS, etc.), used to prioritize security testing, training, and remediation efforts." },
  { id:30465, domain:6, level:2, question:"What is the goal of threat modeling in the software development lifecycle?", options:["A Systematically identifying potential threats, vulnerabilities, and mitigations for an application early in design","B Identifying performance bottlenecks in application architecture","C Creating security test cases for QA testing before deployment","D Documenting known vulnerabilities in application dependencies"], correct:0, explanation:"Threat modeling identifies potential threats (STRIDE: Spoofing, Tampering, Repudiation, Information Disclosure, DoS, Elevation of Privilege) during design, enabling security controls to be built in rather than bolted on." },
  { id:30466, domain:6, level:2, question:"Which metric indicates how quickly an organization detects a security breach after it occurs?", options:["A Mean time to detect (MTTD)","B Mean time to recover (MTTR)","C Recovery point objective (RPO)","D Recovery time objective (RTO)"], correct:0, explanation:"Mean time to detect (MTTD) measures the average time from breach occurrence to detection. Lower MTTD means faster discovery, limiting attacker dwell time and reducing the impact of security incidents." },
  { id:30467, domain:6, level:2, question:"What is the purpose of an independent security review?", options:["A Providing a second opinion on security architecture by the same team that designed it","B Evaluating security controls without bias from an independent party not involved in implementation","C Reviewing security policies annually for regulatory compliance","D Assessing vendor security practices before procurement decisions"], correct:1, explanation:"Independent reviews eliminate conflicts of interest and cognitive biases of the implementation team, providing objective assessment of security controls, architecture decisions, and code quality from a fresh perspective." },
  { id:30468, domain:6, level:2, question:"What does software composition analysis (SCA) examine?", options:["A The logical flow of source code to identify programming errors","B Application configuration settings for security misconfigurations","C Third-party and open-source components for known vulnerabilities and license compliance","D Runtime behavior of applications under load conditions"], correct:2, explanation:"SCA tools inventory open-source and third-party components used in applications, identifying versions with known CVEs (like Log4Shell), checking license compliance, and flagging vulnerable dependencies requiring updates." },
  { id:30469, domain:6, level:2, question:"What is the primary purpose of security regression testing?", options:["A Testing new security features before deployment to production","B Verifying that security controls meet compliance requirements","C Ensuring previously fixed vulnerabilities have not been reintroduced after code changes","D Testing the rollback capabilities of security patch deployments"], correct:2, explanation:"Security regression testing verifies that code changes haven't reintroduced previously fixed vulnerabilities or broken existing security controls, particularly important in agile and continuous delivery environments." },
  { id:30470, domain:6, level:2, question:"What is the key difference between a finding and a recommendation in a security assessment report?", options:["A A finding describes an observed weakness or gap; a recommendation proposes how to address it","B Findings are positive observations; recommendations are negative","C Findings are low-priority items; recommendations are critical items","D Findings are confirmed exploits; recommendations are theoretical concerns"], correct:0, explanation:"In security assessments, findings document observed security weaknesses, gaps, or vulnerabilities (what was found). Recommendations propose specific remediations or improvements to address each finding." },
  { id:30471, domain:7, level:2, question:"What is the primary goal of an incident response plan?", options:["A Preventing all security incidents from occurring","B Prosecuting attackers responsible for security breaches","C Documenting all security incidents for regulatory compliance","D Minimizing damage and recovery time through a structured, coordinated response process"], correct:3, explanation:"An incident response plan provides structured procedures for detecting, containing, eradicating, and recovering from security incidents, minimizing damage, reducing recovery time, and preserving evidence for investigation." },
  { id:30472, domain:7, level:2, question:"Which phase of the incident response lifecycle focuses on limiting an attack's spread after detection?", options:["A Identification","B Containment","C Eradication","D Recovery"], correct:1, explanation:"The containment phase limits the scope and impact of an incident after detection, including isolating affected systems, blocking attacker access, and preventing lateral movement while preserving evidence for forensic analysis." },
  { id:30473, domain:7, level:2, question:"What is the 'chain of custody' in digital forensics?", options:["A The sequence of commands used by an attacker during an intrusion","B The legal process for prosecuting cybercriminals","C The order in which forensic tools are applied to analyze evidence","D Documentation tracking who handled evidence, when, and what was done with it"], correct:3, explanation:"Chain of custody documents every person who handled evidence, when they had it, and what they did with it, ensuring evidence integrity and admissibility in legal proceedings by demonstrating it wasn't tampered with." },
  { id:30474, domain:7, level:2, question:"What is the purpose of a business continuity plan (BCP)?", options:["A Documenting technical recovery procedures for individual IT systems","B Providing legal protection during a significant data breach","C Ensuring critical business functions continue during and after disruptive events","D Backing up all data to prevent loss during system failures"], correct:2, explanation:"A BCP identifies critical business functions and defines how they will be maintained or quickly resumed during disruptive events (disasters, pandemics, system failures), minimizing operational impact." },
  { id:30475, domain:7, level:2, question:"What does Recovery Time Objective (RTO) define?", options:["A The maximum amount of data that can be lost measured in time","B The maximum acceptable time to restore a system or process after a disruption","C The time required to complete a full system backup","D The frequency at which backup tests should be conducted"], correct:1, explanation:"RTO specifies the maximum time a system or business process can be offline after a disruption before the impact becomes unacceptable, driving decisions about redundancy, failover, and recovery prioritization." },
  { id:30476, domain:7, level:2, question:"What does Recovery Point Objective (RPO) define?", options:["A How quickly systems must be recovered after a disaster","B The specific point to which data must be restored","C The maximum acceptable amount of data loss measured in time","D The minimum data retention period required for compliance"], correct:2, explanation:"RPO defines how much data loss is acceptable (measured in time), determining how frequently backups must occur. An RPO of 4 hours means at most 4 hours of data can be lost, requiring backups at least every 4 hours." },
  { id:30477, domain:7, level:2, question:"What is a hot site in disaster recovery planning?", options:["A A remote office location used during evacuations","B A data storage facility containing offline backups of critical data","C A fully equipped, operational duplicate facility that can take over immediately upon primary site failure","D A mobile response team ready to deploy to any disaster location"], correct:2, explanation:"A hot site is a fully redundant facility with live systems, current data, and staff ready to operate immediately, providing the fastest recovery time but at the highest cost. Cold sites have space/power but require setup; warm sites are partially configured." },
  { id:30478, domain:7, level:2, question:"What is the purpose of a disaster recovery test?", options:["A Verifying that backup storage media are not damaged","B Documenting all systems and data for insurance purposes","C Training staff on the use of backup and recovery tools","D Simulating a disaster to evaluate whether recovery procedures work as expected"], correct:3, explanation:"DR tests validate that recovery procedures actually work (RTOs and RPOs can be met), identify gaps in plans, and build staff confidence and competency, ensuring the organization can actually recover when a real disaster occurs." },
  { id:30479, domain:7, level:2, question:"What is the primary purpose of a security operations center (SOC)?", options:["A Managing enterprise IT infrastructure and helpdesk operations","B Conducting security awareness training for all employees","C Developing security policies and compliance programs","D Providing 24/7 monitoring, detection, and response capabilities for security threats"], correct:3, explanation:"A SOC provides continuous monitoring of the security environment, threat detection, incident triage, and coordinated response using analysts, processes, and technologies (SIEM, EDR, SOAR) to protect the organization." },
  { id:30480, domain:7, level:2, question:"What is configuration management in security operations?", options:["A Managing user account configurations in directory services","B Tracking and controlling changes to system configurations to maintain known-good states","C Configuring security tools for optimal detection performance","D Managing software licenses and version updates across the environment"], correct:1, explanation:"Configuration management ensures systems are built to secure baselines, tracks all changes, detects unauthorized modifications (configuration drift), and provides rollback capability, maintaining the integrity of the security posture." },
  { id:30481, domain:7, level:2, question:"What is patch management's primary security objective?", options:["A Minimizing system downtime during software updates","B Remediating known vulnerabilities by applying vendor-released fixes before attackers exploit them","C Ensuring software licensing compliance across all systems","D Maintaining compatibility between different software versions"], correct:1, explanation:"Patch management reduces the attack surface by applying vendor patches that fix known vulnerabilities. Unpatched systems are a primary attack vector—most breaches exploit known vulnerabilities for which patches were available." },
  { id:30482, domain:7, level:2, question:"What is the principle of least functionality in system hardening?", options:["A Systems should be as simple as possible to reduce management overhead","B Security controls should not impact normal system functionality","C Systems should only have the minimum features, services, and capabilities needed for their specific purpose","D Users should only see the features relevant to their job role"], correct:2, explanation:"Least functionality (system hardening) removes or disables all unnecessary features, services, ports, protocols, and accounts from systems, reducing the attack surface by eliminating components an attacker could exploit." },
  { id:30483, domain:7, level:2, question:"What type of backup captures only changes made since the last full backup?", options:["A Incremental backup","B Differential backup","C Full backup","D Mirror backup"], correct:0, explanation:"Incremental backups capture only changes since the last backup of any type (full or incremental), using less storage and time than differential backups, but requiring all incrementals plus the last full for complete restoration." },
  { id:30484, domain:7, level:2, question:"What is the primary security concern with removable media (USB drives)?", options:["A Removable media can introduce malware and facilitate unauthorized data exfiltration","B USB drives are unreliable for long-term data storage","C USB drives are incompatible with encryption standards","D Removable media requires special drivers that create vulnerabilities"], correct:0, explanation:"Removable media presents dual risks: malware introduction (AutoRun attacks, BadUSB) and unauthorized data exfiltration. Organizations typically control USB ports through technical controls and DLP policies." },
  { id:30485, domain:7, level:2, question:"What is threat hunting?", options:["A Automated scanning for vulnerabilities across the network","B Responding to security alerts generated by SIEM correlation rules","C Proactively searching through networks and systems to detect threats that have evaded automated defenses","D Tracking threat actors based on external threat intelligence feeds"], correct:2, explanation:"Threat hunting is a proactive practice where security analysts search for indicators of compromise and attacker behaviors that automated tools missed, using hypothesis-driven investigations and advanced analysis techniques." },
  { id:30486, domain:7, level:2, question:"What is the purpose of network forensics?", options:["A Monitoring real-time network traffic for intrusion attempts","B Capturing and analyzing network traffic to reconstruct events during incident investigation","C Blocking malicious network connections using automated response","D Testing network security controls for weaknesses"], correct:1, explanation:"Network forensics captures and analyzes network traffic (packet captures, NetFlow, DNS logs) to reconstruct the timeline of an attack, identify attacker techniques, determine scope, and gather evidence for legal proceedings." },
  { id:30487, domain:7, level:2, question:"What does mean time between failures (MTBF) measure?", options:["A The time required to repair a failed component","B The maximum acceptable downtime for a critical system","C The average time a component operates between failures, indicating reliability","D The frequency of scheduled maintenance for hardware components"], correct:2, explanation:"MTBF measures the average operating time between failures for repairable systems, indicating reliability. Higher MTBF means more reliable systems. It is used in availability calculations alongside mean time to repair (MTTR)." },
  { id:30488, domain:7, level:2, question:"What is a tabletop exercise in incident response?", options:["A A discussion-based exercise where stakeholders walk through a scenario to identify response gaps","B A simulated cyberattack where technical teams respond in real systems","C A training exercise using physical equipment and response tools","D An automated test of incident response playbooks and systems"], correct:0, explanation:"Tabletop exercises are facilitated discussions where stakeholders verbally walk through an incident scenario, testing awareness of roles, communication, and decision-making without technical execution, identifying gaps in plans and training needs." },
  { id:30489, domain:7, level:2, question:"What is the purpose of an after-action review (lessons learned) following a security incident?", options:["A Identifying what worked, what didn't, and improving processes for future incidents","B Assigning blame for the incident to responsible parties","C Creating legal documentation for regulatory reporting requirements","D Calculating the financial impact for insurance claim purposes"], correct:0, explanation:"After-action reviews analyze the incident response process, identify what went well and what needs improvement, update procedures and playbooks, and apply lessons learned to strengthen future responses." },
  { id:30490, domain:7, level:2, question:"What is a computer security incident response team (CSIRT)?", options:["A A team responsible for security architecture and control design","B A group of analysts performing continuous security monitoring","C A team providing coordinated response capabilities for cybersecurity incidents","D A committee responsible for approving security policies and budgets"], correct:2, explanation:"A CSIRT provides a coordinated, systematic capability for receiving incident reports, coordinating response activities, providing technical expertise, communicating with stakeholders, and managing the incident lifecycle." },
  { id:30491, domain:7, level:2, question:"What does 'indicators of compromise' (IOC) refer to?", options:["A Legal evidence standards for prosecuting cybercrime","B Configuration baselines defining acceptable system states","C Compliance metrics measuring adherence to security policies","D Artifacts or behaviors observed on a network or system that indicate potential compromise"], correct:3, explanation:"IOCs are observable artifacts (malicious IPs, hashes, domains, registry keys, file names) that suggest a system has been compromised. They are used in threat hunting, SIEM rules, and threat intelligence sharing." },
  { id:30492, domain:7, level:2, question:"What is the difference between an event and a security incident?", options:["A Events are external threats; incidents are internal policy violations","B Events are logged automatically; incidents require manual analyst review","C An event is any observable occurrence; an incident is an event that negatively impacts security","D Events affect users; incidents affect systems and infrastructure"], correct:2, explanation:"An event is any observable system or network occurrence (login attempt, file access). An incident is an event that adversely affects security—violating confidentiality, integrity, or availability, or violating policy." },
  { id:30493, domain:7, level:2, question:"What is the primary goal of eradication in the incident response lifecycle?", options:["A Removing all traces of the attacker, malware, and compromise from affected systems","B Documenting the incident for compliance reporting","C Restoring affected systems to normal operation","D Identifying the root cause and attack entry point"], correct:0, explanation:"Eradication removes the root cause of the incident—eliminating malware, closing vulnerabilities exploited, removing attacker backdoors, and resetting compromised credentials—before systems are restored to production." },
  { id:30494, domain:7, level:2, question:"What is write blocking in digital forensics?", options:["A Using hardware or software to prevent any writes to evidence media during forensic acquisition","B Preventing analysts from documenting case findings during investigation","C Restricting write access to forensic tools to prevent accidental modification","D Blocking network writes to prevent evidence destruction during incident response"], correct:0, explanation:"Write blockers prevent any writes to evidence storage media during forensic acquisition and analysis, preserving evidence integrity and ensuring the forensic copy is identical to the original without risking accidental modification." },
  { id:30495, domain:7, level:2, question:"What does the term 'dwell time' refer to in cybersecurity?", options:["A The duration an attacker remains undetected in a compromised environment","B The time required for security analysts to investigate an alert","C The time between vulnerability disclosure and patch availability","D The period during which backup data is retained before deletion"], correct:0, explanation:"Dwell time is how long an attacker remains in a compromised environment before detection. Long dwell times (industry average was historically 200+ days) allow extensive damage—exfiltration, lateral movement, and persistence establishment." },
  { id:30496, domain:7, level:2, question:"What is the MITRE ATT&CK framework?", options:["A A risk management framework for quantifying cybersecurity investment","B A knowledge base of adversary tactics, techniques, and procedures based on real-world observations","C A vulnerability scoring system for prioritizing patch remediation","D A compliance framework for critical infrastructure protection"], correct:1, explanation:"MITRE ATT&CK documents adversary tactics (goals) and techniques (methods) based on observed real-world attacks, providing a common language for threat intelligence, detection development, red team planning, and security assessments." },
  { id:30497, domain:7, level:2, question:"What is the primary goal of data loss prevention (DLP) technology?", options:["A Encrypting all sensitive data at rest and in transit","B Detecting and preventing unauthorized transmission of sensitive data outside the organization","C Backing up critical data to prevent loss from system failures","D Monitoring user access to sensitive data for compliance auditing"], correct:1, explanation:"DLP monitors and controls data in use, in motion, and at rest to prevent unauthorized exfiltration of sensitive data (PII, intellectual property, financial data) through email, USB, cloud upload, or other channels." },
  { id:30498, domain:7, level:2, question:"What is a playbook in security operations?", options:["A A documented set of procedures for responding to specific types of security incidents","B A collection of threat intelligence from external security vendors","C A software tool for automating security monitoring tasks","D A training manual for security operations center analysts"], correct:0, explanation:"Security playbooks document step-by-step response procedures for specific incident types (phishing, ransomware, DDoS), ensuring consistent, efficient, and thorough responses regardless of which analyst handles the incident." },
  { id:30499, domain:7, level:2, question:"What is the purpose of a cyber range in security training?", options:["A A physical facility for testing network hardware configurations","B A platform for sharing threat intelligence between organizations","C A compliance testing environment for certifying security products","D A simulated, isolated environment for practicing security skills and incident response"], correct:3, explanation:"Cyber ranges provide realistic, isolated environments where security professionals can practice offensive and defensive skills, conduct incident response drills, and test security tools without risking production systems." },
  { id:30500, domain:7, level:2, question:"What does 'containment strategy' choice depend on in incident response?", options:["A The number of analysts available to handle the incident","B The cost of isolating affected systems from the network","C The regulatory reporting requirements applicable to the incident","D The need to preserve evidence vs. stop damage, system criticality, and attacker awareness risk"], correct:3, explanation:"Containment strategy balances evidence preservation (not tipping off the attacker by cutting them off) against damage limitation (isolating systems to stop spread), considering business criticality and forensic requirements." }
];
